    29→pub(super) fn generate<'tcx>(
    30→    typeck: &mut TypeChecker<'_, 'tcx>,
    31→    location_map: &DenseLocationMap,
    32→    move_data: &MoveData<'tcx>,
    33→) {
    34→    debug!("liveness::generate");
