    54→    }
    55→    let (relevant_live_locals, boring_locals) =
    56→        compute_relevant_live_locals(typeck.tcx(), &free_regions, typeck.body);
    57→
    58→    trace::trace(typeck, location_map, move_data, relevant_live_locals, boring_locals);
    59→
